import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Оновлення Fabric","description":"Покрокова інструкція з оновлення Fabric.","frontmatter":{"title":"Оновлення Fabric","description":"Покрокова інструкція з оновлення Fabric.","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"uk_ua/1.21.1/players/updating-fabric.md","filePath":"versions/1.21.1/translated/uk_ua/players/updating-fabric.md","lastUpdated":1761424914000}`);var c={name:`uk_ua/1.21.1/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Оновлення Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Оновлення Fabric”">​</a></h1><p>Ця інструкція допоможе вам оновити Fabric для офіційного запускача Minecraft.</p><p>Для програм запуску сторонніх розробників слід ознайомитися з їх документацією.</p><p>Процес оновлення Fabric дуже схожий на процес встановлення Fabric, тому частини цього посібника будуть такими самими, як і посібник <a href="./installing-fabric">Встановлення Fabric</a>.</p><h2 id="why-should-i-update-fabric-loader" tabindex="-1">Чому я повинен оновлювати Fabric Loader? <a class="header-anchor" href="#why-should-i-update-fabric-loader" aria-label="Permalink to “Чому я повинен оновлювати Fabric Loader?”">​</a></h2><p>Нові моди можуть потребувати новішу версію Fabric Loader для роботи, тому важливо мати актуальну версію, щоб мати можливість використовувати найновіші моди.</p><p>Цей посібник стосується лише офіційного запускача Minecraft. Для запускачів сторонніх розробників слід ознайомитися з їх документацією.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Завантажте встановлювач Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Завантажте встановлювач Fabric”">​</a></h2><p>Ви можете завантажити встановлювач Fabric зі <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">сторінки Fabric</a>.</p><p>Якщо ви користуєтеся Windows, завантажте версію <code>.exe</code> (<code>Download For Windows</code>), оскільки для цього не потрібно встановлювати Java у вашій системі. Натомість він використовує Java, яка постачається з офіційним запускачем.</p><p>Для macOS та Linux вам слід завантажити <code>jar</code> версію. Іноді перед цим кроком потрібно встановити Java.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Запустіть встановлювач Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Запустіть встановлювач Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Перш ніж запустити встановлювач, закрийте Minecraft і запускач Minecraft.</p></div><details class="details custom-block"><summary>Інформація для користувачів MacOS</summary><p>У macOS вам може знадобитися натиснути ПКМ по файлу <code>.jar</code> у каталозі завантажень і натиснути <code>Відкрити</code>, щоб запустити його.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Контекстне меню MacOS у Fabric Installer" loading="lazy"></p><p>Коли вас запитають «Ви впевнені, що хочете відкрити?», знову натисніть <code>Відкрити</code>.</p></details><p>Відкривши встановлювач, ви повинні побачити такий екран:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Встановлювач Fabric із виділеним «встановити»" loading="lazy"></p><p>Щоб оновити Fabric, просто переконайтеся, що версія гри та версія завантажувача правильні, а потім натисніть «Встановити».</p><div class="warning custom-block"><p class="custom-block-title">ВАЖЛИВО</p><p>Під час запуску встановлювача обов&#39;язково зніміть прапорець «Створити профіль», інакше буде створено новий профіль, який у цьому випадку нам не потрібен.</p></div><h2 id="3-open-the-profile-in-the-minecraft-launcher" tabindex="-1">3. Відкрийте профіль у запускачі Minecraft <a class="header-anchor" href="#3-open-the-profile-in-the-minecraft-launcher" aria-label="Permalink to “3. Відкрийте профіль у запускачі Minecraft”">​</a></h2><p>Після завершення встановлення ви можете відкрити запускач Minecraft і перейти у вкладку «Встановлення». Ви повинні перейти до свого профілю Fabric і відкрити екран редагування.</p><p>Замініть версію новою версією Fabric Loader, яку ви щойно встановили, і натисніть «Зберегти».</p><p><img src="/assets/players/updating-fabric.png" alt="Оновлення версії Fabric Loader у програмі запуску Minecraft" loading="lazy"></p><h2 id="4-you-re-done" tabindex="-1">4. Готово! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Готово!”">​</a></h2><p>Виконавши кроки, ви можете повернутися на вкладку <code>Play</code>, вибрати профіль Fabric зі спадного меню в нижньому лівому куті та натиснути кнопку грати!</p><p>Якщо під час виконання цього посібника у вас виникнуть проблеми, ви можете звернутися за допомогою до <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> на каналі <code>#player-support</code>.</p>`,25)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};